function shortestCompletingWord(licensePlate, words) {
  const lpCount = new Map();
  for (const c of licensePlate)
    if (c.match(/[a-zA-Z]/))
      lpCount.set(c.toLowerCase(), (lpCount.get(c.toLowerCase()) || 0) + 1);

  let result = "";
  for (const word of words) {
    const wordCount = new Map();
    for (const c of word)
      wordCount.set(c, (wordCount.get(c) || 0) + 1);

    let valid = true;
    for (const [ch, count] of lpCount)
      if ((wordCount.get(ch) || 0) < count) {
        valid = false;
        break;
      }

    if (valid && (!result || word.length < result.length))
      result = word;
  }
  return result;
}
```


    1. Create a hash map (or dictionary in Python) to store the count of characters in the `licensePlate`.
2. Iterate through the `words` array.
   1. For each word, create a hash map storing the count of characters in the current word.
   2. Check whether the current word is a valid completing word by comparing the counts in both hash maps. It's valid if it has equal or more count of characters compared to the `licensePlate` for each character.
   3. If the word is valid and the result is empty or the length of the word is shorter than the result's length, update the result with the current word.
3. Return the result.

